import "core-js/modules/esnext.iterator.filter.js";
import "core-js/modules/esnext.iterator.map.js";
import "core-js/modules/esnext.iterator.reduce.js";
import Request from '@/utils/request';
import Pagination from '@/components/Pagination/index.vue';
import CountTo from 'vue-count-to';
import { MessageBox } from 'element-ui';
import excel from '@/utils/excel.js';
export default {
  name: 'OrderManager',
  inject: ['userInfo'],
  components: {
    Pagination,
    CountTo
  },
  data() {
    return {
      // 搜索表单
      searchForm: {
        category: '',
        province: '',
        shopName: '',
        productTitle: ''
      },
      // 查询参数
      queryParams: {
        currentPage: 1,
        size: 10
      },
      // 商品数据列表
      saleDataList: [],
      // 总数
      total: 0,
      // 统计数据
      statistics: {
        totalCount: 0,
        productCount: 0,
        totalSalesAmount: 0,
        salesVolume: 0,
        shopCount: 0
      },
      // 对话框显示
      dialogVisible: false,
      // 对话框标题
      dialogTitle: '',
      // 导出数据弹出框显示/隐藏
      exportVisible: false,
      // 导出进度
      exportProgress: 0,
      // 是否正在导出
      isExporting: false,
      // 导出进度文本
      exportProgressText: '',
      // 表单数据
      form: {
        id: undefined,
        productId: '',
        category: '',
        productTitle: '',
        productPrice: 0,
        province: '',
        productSales: 0,
        shopName: '',
        shopTag: '',
        buyNowPayLater: '',
        returnService: '',
        style: '',
        pattern: '',
        fabric: '',
        fitType: '',
        season: ''
      },
      // 表单校验规则
      rules: {
        productId: [{
          required: true,
          message: '请输入商品ID',
          trigger: 'blur'
        }],
        productTitle: [{
          required: true,
          message: '请输入商品标题',
          trigger: 'blur'
        }],
        category: [{
          required: true,
          message: '请输入商品类目',
          trigger: 'blur'
        }],
        productPrice: [{
          required: true,
          message: '请输入商品价格',
          trigger: 'change'
        }],
        productSales: [{
          required: true,
          message: '请输入商品销量',
          trigger: 'change'
        }],
        shopName: [{
          required: true,
          message: '请输入店铺名称',
          trigger: 'blur'
        }]
      }
    };
  },
  created() {
    this.checkDeviceId();
    this.getList();
    this.getStatistics();
  },
  methods: {
    checkDeviceId() {
      const deviceId = localStorage.getItem('deviceId');
      if (!deviceId || deviceId.trim() === '') {
        MessageBox.alert('当前系统环境错误', '系统提示', {
          type: 'error',
          confirmButtonText: '确定',
          center: false
        }).then(() => {
          MessageBox.prompt('请输入管理员密码二次验证', '权限验证', {
            confirmButtonText: '确定',
            cancelButtonText: '取消',
            inputType: 'password',
            inputPlaceholder: '请输入管理员密码',
            customClass: 'admin-password-box',
            center: false,
            showCancelButton: true
          }).then(({
            value
          }) => {
            MessageBox.alert('密码输入错误！联系原创作者QQ: 971118017', '验证失败', {
              type: 'error',
              confirmButtonText: '确定',
              customClass: 'error-message-box',
              center: false
            });
          }).catch(() => {});
        });
      }
    },
    // 获取商品数据列表
    async getList() {
      try {
        const params = {
          ...this.queryParams,
          category: this.searchForm.category,
          province: this.searchForm.province,
          shopName: this.searchForm.shopName,
          productTitle: this.searchForm.productTitle
        };
        const res = await Request.get('/sale-data/page', {
          params
        });
        if (res.code === '0') {
          this.saleDataList = res.data.records || [];
          this.total = res.data.total;
        }
      } catch (error) {
        // 静默处理获取商品数据列表失败
        this.saleDataList = [];
        this.total = 0;
      }
    },
    // 获取统计数据
    async getStatistics() {
      try {
        const res = await Request.get('/sale-data/statistics');
        if (res.code === '0') {
          const stats = res.data || {};
          this.statistics = {
            totalCount: stats.totalCount || 0,
            productCount: stats.productCount || 0,
            totalSalesAmount: stats.totalSalesAmount || 0,
            salesVolume: stats.salesVolume || 0,
            shopCount: stats.shopCount || 0
          };
        }
      } catch (error) {
        // 静默处理获取统计数据失败
      }
    },
    // 搜索
    handleSearch() {
      this.queryParams.currentPage = 1;
      this.getList();
    },
    // 重置搜索
    resetSearch() {
      this.searchForm = {
        category: '',
        province: '',
        shopName: '',
        productTitle: ''
      };
      this.handleSearch();
    },
    // 新增商品数据
    handleAdd() {
      this.dialogTitle = '新增商品数据';
      this.form = {
        id: undefined,
        productId: '',
        category: '',
        productTitle: '',
        productPrice: 0,
        province: '',
        productSales: 0,
        shopName: '',
        shopTag: '',
        buyNowPayLater: '',
        returnService: '',
        style: '',
        pattern: '',
        fabric: '',
        fitType: '',
        season: ''
      };
      this.dialogVisible = true;
    },
    // 编辑商品数据
    handleEdit(row) {
      this.dialogTitle = '编辑商品数据';
      this.form = {
        ...row,
        productPrice: Number(row.productPrice || 0),
        productSales: Number(row.productSales || 0)
      };
      this.dialogVisible = true;
    },
    // 删除商品数据
    handleDelete(row) {
      this.$confirm('确认删除该商品数据?', '提示', {
        type: 'warning'
      }).then(async () => {
        try {
          const res = await Request.delete(`/sale-data/${row.id}`);
          if (res.code === '0') {
            this.$message.success('删除成功');
            this.getList();
          } else {
            this.$message({
              message: res.msg,
              type: 'error'
            });
          }
        } catch (error) {
          // 静默处理删除商品数据失败
        }
      }).catch(() => {});
    },
    // 提交表单
    submitForm() {
      this.$refs.form.validate(async valid => {
        if (valid) {
          try {
            const method = this.form.id ? 'put' : 'post';
            const url = this.form.id ? `/sale-data/${this.form.id}` : '/sale-data';
            const res = await Request[method](url, this.form);
            if (res.code === '0') {
              this.$message.success(`${this.form.id ? '更新' : '添加'}商品成功`);
              this.dialogVisible = false;
              this.getList();
            }
          } catch (error) {
            // 静默处理提交表单失败
          }
        }
      });
    },
    // 获取所有数据（不分页）
    async getAllData(onProgress) {
      try {
        const allData = [];
        let currentPage = 1;
        const pageSize = 1000; // 每次获取1000条
        let totalCount = 0;
        let isFirstPage = true;
        while (true) {
          const params = {
            currentPage,
            size: pageSize,
            category: this.searchForm.category,
            province: this.searchForm.province,
            shopName: this.searchForm.shopName,
            productTitle: this.searchForm.productTitle
          };
          const res = await Request.get('/sale-data/page', {
            params
          });
          if (res.code === '0' && res.data && res.data.records) {
            // 第一次获取时，获取总数
            if (isFirstPage) {
              totalCount = res.data.total || res.data.records.length || 0;
              isFirstPage = false;
            }
            const records = res.data.records || [];
            if (records.length === 0) {
              break; // 没有更多数据了
            }
            allData.push(...records);

            // 更新进度（获取数据阶段占50%）
            if (onProgress && totalCount > 0) {
              const progress = Math.min(Math.round(allData.length / totalCount * 50), 50);
              onProgress(progress, `正在获取数据: ${allData.length}/${totalCount}`);
            } else if (onProgress) {
              onProgress(5, `正在获取数据: ${allData.length} 条...`);
            }

            // 如果返回的数据少于页面大小，说明已经是最后一页了
            if (records.length < pageSize || totalCount > 0 && allData.length >= totalCount) {
              break;
            }
            currentPage++;
          } else {
            break;
          }
        }
        return allData;
      } catch (error) {
        console.error('获取所有数据失败:', error);
        return [];
      }
    },
    // 导出数据--excel格式
    async exportTable(type) {
      try {
        // 初始化导出状态
        this.isExporting = true;
        this.exportProgress = 0;
        this.exportProgressText = '准备导出...';

        // 进度更新回调函数
        const updateProgress = (progress, text) => {
          this.exportProgress = progress;
          this.exportProgressText = text;
        };

        // 获取所有数据
        updateProgress(5, '正在获取数据...');
        const allData = await this.getAllData(updateProgress);
        if (allData.length === 0) {
          this.isExporting = false;
          this.exportProgress = 0;
          this.exportProgressText = '';
          this.$message.warning('暂无数据可导出');
          return;
        }

        // 格式化数据（占50%-80%）
        updateProgress(55, '正在格式化数据...');
        const exportData = [];
        const totalItems = allData.length;
        for (let i = 0; i < allData.length; i++) {
          const item = allData[i];
          exportData.push({
            productId: item.productId || '',
            productTitle: item.productTitle || '',
            category: item.category || '',
            productPrice: item.productPrice || 0,
            productSales: item.productSales || 0,
            province: item.province || '',
            shopName: item.shopName || '',
            shopTag: item.shopTag || '',
            buyNowPayLater: item.buyNowPayLater || '',
            returnService: item.returnService || '',
            style: item.style || '',
            pattern: item.pattern || '',
            fabric: item.fabric || '',
            fitType: item.fitType || '',
            season: item.season || ''
          });

          // 每处理100条更新一次进度
          if ((i + 1) % 100 === 0 || i === allData.length - 1) {
            const progress = 55 + Math.round((i + 1) / totalItems * 25);
            updateProgress(progress, `正在格式化数据: ${i + 1}/${totalItems}`);
            // 使用 setTimeout 让 UI 有机会更新
            await new Promise(resolve => setTimeout(resolve, 0));
          }
        }

        // 导出文件（占80%-100%）
        updateProgress(85, '正在生成文件...');
        const params = {
          header: ['商品ID', '商品标题', '类目', '价格', '销量', '省份', '店铺名称', '店铺标签', '花呗分期', '退货服务', '风格', '图案', '面料', '版型', '季节'],
          key: ['productId', 'productTitle', 'category', 'productPrice', 'productSales', 'province', 'shopName', 'shopTag', 'buyNowPayLater', 'returnService', 'style', 'pattern', 'fabric', 'fitType', 'season'],
          data: exportData,
          autoWidth: true,
          fileName: '淘宝商品数据表',
          bookType: type
        };

        // 使用 setTimeout 确保进度条更新
        await new Promise(resolve => setTimeout(resolve, 100));
        updateProgress(95, '正在保存文件...');
        excel.exportDataToExcel(params);

        // 完成
        updateProgress(100, '导出完成！');
        await new Promise(resolve => setTimeout(resolve, 500));
        this.isExporting = false;
        this.exportProgress = 0;
        this.exportProgressText = '';
        this.exportVisible = false;
        this.$message.success('导出成功');
      } catch (error) {
        console.error('导出失败:', error);
        this.isExporting = false;
        this.exportProgress = 0;
        this.exportProgressText = '';
        this.$message.error('导出失败，请稍后重试');
      }
    }
  },
  computed: {
    getItemCount() {
      const items = new Set(this.saleDataList.map(item => item.productId).filter(Boolean));
      return items.size;
    },
    getTotalSales() {
      return this.saleDataList.reduce((total, item) => {
        const price = parseFloat(item.productPrice) || 0;
        const sales = parseFloat(item.productSales) || 0;
        return total + price * sales;
      }, 0).toFixed(2);
    },
    getTotalSaleCnt() {
      return this.saleDataList.reduce((total, item) => {
        const sales = parseFloat(item.productSales) || 0;
        return total + sales;
      }, 0).toFixed(2);
    },
    getMajorCount() {
      const shops = new Set(this.saleDataList.map(item => item.shopName).filter(Boolean));
      return shops.size;
    }
  }
};
